import java.net.http.*;
import java.net.URI;
public class App {
    public static void main(String[] args) {
        String jsonBody = "{\"product\":\"Mouse\",\"qty\":2,\"price\":799}";
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("https://api.example.com/v1/orders"))
            .POST(HttpRequest.BodyPublishers.ofString(jsonBody))
            .header("Content-Type", "application/json")
            .header("Accept",       "application/json")
            .build();
        System.out.println("Method: "       + request.method());
        System.out.println("URI: "          + request.uri());
        System.out.println("Content-Type: " + request.headers().firstValue("Content-Type").orElse("none"));
        System.out.println("Body present: " + request.bodyPublisher().isPresent());
    }
}

public class App {
    static String handleResponse(int statusCode, String body) {
        return switch (statusCode) {
            case 200 -> "OK — parsing body";
            case 201 -> "Created — new resource id extracted";
            case 404 -> "Not found — returning empty";
            case 429 -> "Rate limited — retry later";
            case 500, 502, 503 -> "Server error — retry later";
            default  -> "Unexpected status: " + statusCode;
        };
    }
    public static void main(String[] args) {
        for (int code : new int[]{200, 201, 404, 500}) {
            System.out.println(code + ": " + handleResponse(code, "{}"));
        }
    }
}

