    static void fetchAndDisplay(String symbol) throws Exception {
        String body = MOCK_API.get(symbol);  // In real code: response.body()
        JsonNode json = MAPPER.readTree(body);
        System.out.printf("%-12s ₹%,d  %+.1f%%%n",
            json.path("symbol").asText(),
            json.path("price").asInt(),
