public class App {
    record Product(String id, String name, int price) {}

    static class ProductApiClient {
        private static final ObjectMapper MAPPER = new ObjectMapper();
        // In real code: private static final HttpClient HTTP = HttpClient.newBuilder()...

        // Simulate different API responses:
        static Optional<Product> getProduct(String id) {
            // Mock different scenarios:
            if (id.equals("P001")) {
                try {
                    String json = "{\"id\":\"P001\",\"name\":\"Wireless Mouse\",\"price\":799}";
                    // In real code: check response.statusCode() == 200
                    Product p = MAPPER.readValue(json, Product.class);
                    return Optional.of(p);
                } catch (Exception e) { return Optional.empty(); }
            } else if (id.equals("P999")) {
                return Optional.empty();  // Simulates HTTP 404
            } else {
                System.err.println("Fetch " + id + " error: HTTP 500");
                return Optional.empty();
            }
        }
