    public static void main(String[] args) {
        ProductApiClient.getProduct("P001")
            .ifPresentOrElse(
                p -> System.out.printf("Found %s: %s ₹%d%n", p.id(), p.name(), p.price()),
                () -> System.out.println("P001: not found"));
        ProductApiClient.getProduct("P999")
            .ifPresentOrElse(
                p -> System.out.println("Found: " + p.name()),
                () -> System.out.println("P999: not found"));
        ProductApiClient.getProduct("P002");
