import java.net.http.*;
import java.net.URI;
public class App {
    static String buildUrl(String base, String... params) {
        StringBuilder sb = new StringBuilder(base + "?");
        for (int i = 0; i < params.length - 1; i += 2) {
            if (i > 0) sb.append("&");
            sb.append(params[i]).append("=").append(params[i+1]);
        }
        return sb.toString();
    }

    public static void main(String[] args) {
        String base = "https://api.example.com/api/products";

        String url1 = buildUrl(base, "category","Electronics", "limit","10");
        HttpRequest req1 = HttpRequest.newBuilder().uri(URI.create(url1)).GET().build();
        System.out.println("Search 1: " + req1.method() + " " + req1.uri().getRawPath() + "?" + req1.uri().getRawQuery());

        String url2 = buildUrl(base, "minPrice","500", "maxPrice","2000", "sortBy","price");
        HttpRequest req2 = HttpRequest.newBuilder().uri(URI.create(url2)).GET().build();
        System.out.println("Search 2: " + req2.method() + " " + req2.uri().getRawPath() + "?" + req2.uri().getRawQuery());
    }
}

public class App {
    static int attempt = 0;

    // Simulates HTTP response codes:
    static int simulatedStatusCode() {
        attempt++;
        return attempt < 3 ? 429 : 200;
    }

    static String fetchWithRetry(String url, int maxRetries) throws InterruptedException {
        for (int i = 1; i <= maxRetries; i++) {
            // In real code: HttpResponse<String> response = HTTP.send(request, ...);
            int status = simulatedStatusCode();
            if (status == 200) {
                System.out.println("Attempt " + i + ": 200 OK — got response");
                return "response data";
            } else if (status == 429) {
                System.out.println("Attempt " + i + ": 429 Rate limited, waiting 100ms...");
                Thread.sleep(100);
            } else {
                throw new RuntimeException("Unrecoverable error: " + status);
            }
        }
        throw new RuntimeException("Max retries exceeded");
    }

    public static void main(String[] args) throws Exception {
        String result = fetchWithRetry("https://api.example.com/data", 5);
        System.out.println("Fetch succeeded after " + attempt + " attempts");
    }
}

