import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
public class App {
    static final ObjectMapper MAPPER = new ObjectMapper();

    // Simulate POST /v1/orders response:
    static String simulateCreateOrder(int amount, String currency) throws Exception {
        ObjectNode resp = MAPPER.createObjectNode();
        resp.put("id",       "ord_ABC123");
        resp.put("amount",   amount);
        resp.put("currency", currency);
        resp.put("status",   "created");
        return MAPPER.writeValueAsString(resp);
    }

    // Simulate GET /v1/orders/{id} response:
    static String simulateGetOrder(String orderId) throws Exception {
        ObjectNode resp = MAPPER.createObjectNode();
        resp.put("id",       orderId);
        resp.put("status",   "CREATED");
        resp.put("amount",   1500);
        ObjectNode customer = MAPPER.createObjectNode();
        customer.put("name", "Aisha").put("email", "aisha@example.com");
        resp.set("customer", customer);
        resp.put("expiresAt", "2024-03-15T11:00:00");
        return MAPPER.writeValueAsString(resp);
    }

    public static void main(String[] args) throws Exception {
        // Step 1: Create order (POST)
        System.out.println("Creating order for ₹1500...");
        String createBody = simulateCreateOrder(1500, "INR");
        JsonNode createResp = MAPPER.readTree(createBody);
        // (HTTP 201 in real code)
        String orderId = createResp.path("id").asText();
        System.out.println("Order created: " + orderId);

        // Step 2: Fetch status (GET)
        System.out.println("Fetching status for " + orderId + "...");
        String getBody = simulateGetOrder(orderId);
        JsonNode order = MAPPER.readTree(getBody);
        // (HTTP 200 in real code)
        System.out.println("Payment Status: " + order.path("status").asText());
        System.out.println("Amount: ₹" + order.path("amount").asInt());
        System.out.println("Customer: " +
            order.path("customer").path("name").asText() + " (" +
            order.path("customer").path("email").asText() + ")");
        System.out.println("Valid until: " + order.path("expiresAt").asText());
    }
}
